import streamlit as st
import math
from datetime import datetime, timedelta

CARBOO_AVATAR = "data:image/png;base64,"

# ─── COACH STAPPEN ────────────────────────────────────────────────────────────
STAPPEN = ["welkom","atleet_profiel","wedstrijd_info","carboloading","racedag_voeding","raceplan","samenvatting"]

SPORT_ICONS = {"Fietsen":"🚴","Lopen":"🏃","Duatlon":"🏃🚴","Triatlon":"🏊🚴","Crosstriatlon":"🚵"}

KH_TARGETS = {
    "Fietsen":      {(0,75):(0,0),(75,120):(30,60),(120,180):(60,90),(180,9999):(85,110)},
    "Lopen":        {(0,60):(0,0),(60,90):(30,60),(90,180):(60,90),(180,9999):(75,90)},
    "Duatlon":      {(0,60):(0,0),(60,120):(30,60),(120,9999):(60,90)},
    "Triatlon":     {(0,90):(0,0),(90,180):(60,90),(180,9999):(80,110)},
    "Crosstriatlon":{(0,90):(0,0),(90,180):(60,90),(180,9999):(75,100)},
}

def _get_kh_range(sport, minuten):
    ranges = KH_TARGETS.get(sport, KH_TARGETS["Fietsen"])
    for (lo, hi), (mn, mx) in ranges.items():
        if lo <= minuten < hi:
            return mn, mx
    return 60, 90


def _progress_bar(stap_idx: int):
    total = len(STAPPEN) - 1
    pct = int((stap_idx / total) * 100)
    labels = ["Welkom", "Profiel", "Wedstrijd", "Carboloading", "Racedag", "Raceplan", "Samenvatting"]
    st.markdown(f"""
    <div style="margin-bottom:24px;">
        <div style="display:flex; justify-content:space-between; margin-bottom:6px;">
            <span style="color:#94a3b8; font-size:0.72rem; font-weight:700; letter-spacing:1px;">STAP {stap_idx + 1} VAN {total + 1}</span>
            <span style="color:#f97316; font-size:0.72rem; font-weight:700;">{pct}% VOLTOOID</span>
        </div>
        <div style="background:#1e293b; border-radius:8px; height:8px; overflow:hidden;">
            <div style="width:{pct}%; height:100%; background:linear-gradient(90deg,#f97316,#fb923c); border-radius:8px; transition:width 0.3s;"></div>
        </div>
        <div style="display:flex; justify-content:space-between; margin-top:8px; flex-wrap:wrap; gap:4px;">
            {"".join(f'<span style="font-size:0.65rem; color:{"#f97316" if i == stap_idx else "#334155" if i > stap_idx else "#22c55e"}; font-weight:700;">{lbl}</span>' for i, lbl in enumerate(labels))}
        </div>
    </div>
    """, unsafe_allow_html=True)


def _coach_bubble(tekst: str, extra_klein: bool = False):
    """Coach bubble met de echte Carboo avatar links."""
    grootte = "70px" if extra_klein else "90px"
    col_av, col_txt = st.columns([1, 8])
    with col_av:
        st.markdown(
            f'<img src="{CARBOO_AVATAR}" style="height:{grootte};width:auto;'
            f'filter:drop-shadow(0 0 10px rgba(249,115,22,0.5));display:block;">',
            unsafe_allow_html=True
        )
    with col_txt:
        st.markdown(
            f'<div style="background:#1e293b;border:1px solid #334155;'
            f'border-radius:0 16px 16px 16px;padding:16px 20px;'
            f'color:#f8fafc;font-size:0.92rem;line-height:1.65;'
            f'margin-top:4px;">{tekst}</div>',
            unsafe_allow_html=True
        )


def _info_card(titel, waarde, kleur="#f97316", icon=""):
    st.markdown(f"""
    <div style="background:#1e293b; border-left:4px solid {kleur}; border-radius:10px;
         padding:14px 16px; margin-bottom:10px;">
        <div style="font-size:0.68rem; color:#64748b; font-weight:700; letter-spacing:1px; margin-bottom:2px;">{icon} {titel.upper()}</div>
        <div style="font-size:1.05rem; font-weight:800; color:#f8fafc;">{waarde}</div>
    </div>
    """, unsafe_allow_html=True)


# ─── STAP 0: WELKOM ──────────────────────────────────────────────────────────
def _stap_welkom(naam: str):
    _coach_bubble(f"""
    Hoi <strong>{naam}</strong>! Ik ben <strong>Carboo</strong>, jouw persoonlijke race nutrition coach.<br><br>
    Ik ga je stap voor stap begeleiden om jouw voeding optimaal af te stemmen op je komende wedstrijd.
    We bouwen samen een <strong>volledig voedingsplan</strong> op:<br><br>
    <span style="color:#f97316;">&#x25CF;</span> <strong>Carbohydrate loading</strong> — de 2 dagen voor de race<br>
    <span style="color:#3b82f6;">&#x25CF;</span> <strong>Racedag voeding</strong> — ontbijt en pre-race strategie<br>
    <span style="color:#22c55e;">&#x25CF;</span> <strong>Slim raceplan</strong> — uur per uur wat je eet en drinkt<br><br>
    Dit duurt slechts <strong>5–7 minuten</strong>. Ben je er klaar voor?
    """)
    col1, col2 = st.columns(2)
    with col1:
        if st.button("JA, LET'S GO!", key="welkom_ja", use_container_width=True):
            st.session_state.coach_stap = 1
            st.rerun()
    with col2:
        if st.button("Bekijk eerder plan", key="welkom_plan", use_container_width=True):
            if st.session_state.get("coach_data"):
                st.session_state.coach_stap = 6
                st.rerun()
            else:
                st.info("Nog geen eerder plan gevonden. Start een nieuw plan!")


# ─── STAP 1: PROFIEL ─────────────────────────────────────────────────────────
def _stap_profiel(naam: str):
    _coach_bubble(f"""
    Laten we starten met jouw <strong>atleetprofiel</strong>. Dit helpt me om je koolhydraatbehoeften
    nauwkeurig te berekenen. Vul de gegevens zo nauwkeurig mogelijk in.
    """)
    col1, col2 = st.columns(2)
    with col1:
        gewicht = st.number_input("Lichaamsgewicht (kg)", 30.0, 150.0,
            st.session_state.get("coach_data", {}).get("gewicht", 70.0), 0.5, key="p_gewicht")
    with col2:
        sport_list = list(SPORT_ICONS.keys())
        sport_default = st.session_state.get("coach_data", {}).get("sport", "Fietsen")
        sport_idx = sport_list.index(sport_default) if sport_default in sport_list else 0
        sport = st.selectbox("Discipline", sport_list, index=sport_idx, key="p_sport")

    niveau_list = ["Recreatief", "Competitief", "Elite / Semi-pro"]
    niveau_default = st.session_state.get("coach_data", {}).get("niveau", "Recreatief")
    niveau_idx = niveau_list.index(niveau_default) if niveau_default in niveau_list else 0
    niveau = st.selectbox("Sportniveau", niveau_list, index=niveau_idx, key="p_niveau")

    erv_list = ["Eerste wedstrijd", "1-3 wedstrijden", "4-10 wedstrijden", "10+ wedstrijden"]
    erv_default = st.session_state.get("coach_data", {}).get("ervaring", "Eerste wedstrijd")
    erv_idx = erv_list.index(erv_default) if erv_default in erv_list else 0
    ervaring = st.selectbox("Ervaring met wedstrijdvoeding", erv_list, index=erv_idx, key="p_erv")

    st.markdown("<br>", unsafe_allow_html=True)
    col_prev, col_next = st.columns(2)
    with col_prev:
        if st.button("Vorige", key="prof_prev"):
            st.session_state.coach_stap = 0
            st.rerun()
    with col_next:
        if st.button("Volgende", key="prof_next", use_container_width=True):
            if "coach_data" not in st.session_state:
                st.session_state.coach_data = {}
            st.session_state.coach_data.update({
                "gewicht": gewicht, "sport": sport,
                "niveau": niveau, "ervaring": ervaring,
            })
            st.session_state.coach_stap = 2
            st.rerun()


# ─── STAP 2: WEDSTRIJD ───────────────────────────────────────────────────────
def _stap_wedstrijd():
    data = st.session_state.get("coach_data", {})
    _coach_bubble("""
    Nu de <strong>wedstrijddetails</strong>. Op basis van de duur en het type wedstrijd bereken ik
    hoeveel koolhydraten je nodig hebt en stel ik een tijdlijn op.
    """)
    col1, col2, col3 = st.columns(3)
    with col1:
        wedstrijd_datum = st.date_input("Wedstrijddatum",
            value=datetime.now().date() + timedelta(days=14), key="w_datum")
    with col2:
        start_time = st.time_input("Starttijd",
            value=datetime.strptime(data.get("start_time", "09:00"), "%H:%M").time(), key="w_start")
    with col3:
        eind_time = st.time_input("Geschatte eindtijd",
            value=datetime.strptime(data.get("eind_time", "12:00"), "%H:%M").time(), key="w_eind")

    col4, col5 = st.columns(2)
    with col4:
        temp = st.number_input("Verwachte temperatuur (°C)", -10, 50, data.get("temp", 18), key="w_temp")
    with col5:
        vochtigheid = st.number_input("Vochtigheid (%)", 0, 100, data.get("vochtigheid", 50), key="w_vocht")
    hoogte = st.number_input("Hoogte boven zeeniveau (m)", 0, 5000, data.get("hoogte", 0), key="w_hoogte")

    start_dt = datetime.combine(datetime.today(), start_time)
    eind_dt = datetime.combine(datetime.today(), eind_time)
    if eind_dt <= start_dt:
        eind_dt += timedelta(days=1)
    totale_min = int((eind_dt - start_dt).total_seconds() / 60)
    sport = data.get("sport", "Fietsen")
    min_kh, max_kh = _get_kh_range(sport, totale_min)

    st.markdown(f"""
    <div style="background:rgba(59,130,246,0.1); border:1px solid #3b82f6; padding:14px;
         border-radius:10px; margin:16px 0; text-align:center; color:#93c5fd; font-weight:700;">
        Duur: {totale_min // 60}u{totale_min % 60:02d}m &nbsp;|&nbsp;
        {math.ceil(totale_min/60)} uur te plannen
    </div>
    """, unsafe_allow_html=True)

    col_prev, col_next = st.columns(2)
    with col_prev:
        if st.button("Vorige", key="wed_prev"):
            st.session_state.coach_stap = 1
            st.rerun()
    with col_next:
        if st.button("Volgende", key="wed_next", use_container_width=True):
            st.session_state.coach_data.update({
                "wedstrijd_datum": str(wedstrijd_datum),
                "start_time": start_time.strftime("%H:%M"),
                "eind_time": eind_time.strftime("%H:%M"),
                "totale_min": totale_min, "temp": temp,
                "vochtigheid": vochtigheid, "hoogte": hoogte,
                "min_kh": min_kh, "max_kh": max_kh,
            })
            st.session_state.coach_stap = 3
            st.rerun()


# ─── STAP 3: CARBOLOADING ────────────────────────────────────────────────────
def _stap_carboloading():
    import random
    data = st.session_state.get("coach_data", {})
    gewicht = data.get("gewicht", 70)
    totale_min = data.get("totale_min", 180)
    if totale_min > 300: factor = 12
    elif totale_min > 180: factor = 10
    elif totale_min > 90: factor = 8
    else: factor = 6
    dag_target = round(gewicht * factor)

    _coach_bubble(f"""
    Op basis van jouw gewicht van <strong>{gewicht}kg</strong> en een wedstrijdduur van
    <strong>{totale_min // 60}u{totale_min % 60:02d}min</strong> is jouw dagdoelstelling:
    <strong style="color:#f97316; font-size:1.2rem;"> {dag_target}g koolhydraten/dag</strong><br><br>
    Vul hieronder per maaltijdmoment de producten in die je plant te eten.
    """)

    # ─── FOOD DATABASE ─────────────────────────────────────────────────────
    # label = beschrijvende portie-eenheid  |  carbs = KH per 1 eenheid (gram)
    FOOD_DB = {
        "Wit brood":             {"unit": "sneden",      "label": "1 snede (~35g)  →  15g KH",      "carbs": 15},
        "Bruin brood":           {"unit": "sneden",      "label": "1 snede (~35g)  →  14g KH",      "carbs": 14},
        "Pistolet":              {"unit": "stuks",       "label": "1 pistolet (~60g)  →  26g KH",   "carbs": 26},
        "Koffiekoek":            {"unit": "stuks",       "label": "1 koek (~80g)  →  35g KH",       "carbs": 35},
        "Havermout":             {"unit": "soeplepels",  "label": "1 soeplepel (~15g)  →  8g KH",   "carbs": 8},
        "Ontbijtgranen":         {"unit": "porties",     "label": "1 portie (~40g)  →  30g KH",     "carbs": 30},
        "Granola":               {"unit": "soeplepels",  "label": "1 soeplepel (~20g)  →  12g KH",  "carbs": 12},
        "Banaan":                {"unit": "stuks",       "label": "1 banaan (~120g)  →  25g KH",    "carbs": 25},
        "Jam/Confituur":         {"unit": "koffielepels","label": "1 koffielepel (~15g)  →  7g KH", "carbs": 7},
        "Honing":                {"unit": "koffielepels","label": "1 koffielepel (~10g)  →  6g KH", "carbs": 6},
        "Chocopasta":            {"unit": "koffielepels","label": "1 koffielepel (~15g)  →  10g KH","carbs": 10},
        "Pasta (bijgerecht)":    {"unit": "porties",     "label": "1 portie (~150g bereide)  →  45g KH",  "carbs": 45},
        "Pasta (hoofdgerecht)":  {"unit": "porties",     "label": "1 portie (~300g bereide)  →  90g KH",  "carbs": 90},
        "Rijst":                 {"unit": "eetlepels",   "label": "1 eetlepel (~23g bereide)  →  6g KH",  "carbs": 6},
        "Aardappelen":           {"unit": "stuks",       "label": "1 aardappel (~125g)  →  20g KH", "carbs": 20},
        "Wrap":                  {"unit": "stuks",       "label": "1 wrap (~65g)  →  25g KH",       "carbs": 25},
        "Appelmoes":             {"unit": "potjes",      "label": "1 potje (~100g)  →  22g KH",     "carbs": 22},
        "Couscous":              {"unit": "soeplepels",  "label": "1 soeplepel (~40g bereide)  →  10g KH", "carbs": 10},
        "Quinoa":                {"unit": "soeplepels",  "label": "1 soeplepel (~45g bereide)  →  11g KH", "carbs": 11},
        "Fruit":                 {"unit": "stuks",       "label": "1 stuk (~125g)  →  15g KH",      "carbs": 15},
        "Granenkoek":            {"unit": "stuks",       "label": "1 koek (~35g)  →  20g KH",       "carbs": 20},
        "Peperkoek":             {"unit": "sneden",      "label": "1 snede (~30g)  →  18g KH",      "carbs": 18},
        "Rijstwafel":            {"unit": "stuks",       "label": "1 rijstwafel (~10g)  →  7g KH",  "carbs": 7},
        "Gedroogde abrikozen":   {"unit": "stuks",       "label": "1 abrikoos (~8g)  →  4g KH",     "carbs": 4},
        "Sportdrank":            {"unit": "ml",          "label": "100ml  →  ~7g KH",               "carbs": 0.07},
    }

    MOMENT_CONFIGS = {
        "Ontbijt":       {"pct": 0.25,  "emoji": "🌅", "foods": ["Wit brood","Bruin brood","Pistolet","Koffiekoek","Havermout","Ontbijtgranen","Granola","Banaan","Jam/Confituur","Honing","Chocopasta","Sportdrank"]},
        "Tussendoor VM": {"pct": 0.083, "emoji": "🍌", "foods": ["Banaan","Fruit","Granenkoek","Peperkoek","Rijstwafel","Gedroogde abrikozen","Sportdrank"]},
        "Lunch":         {"pct": 0.25,  "emoji": "🥗", "foods": ["Pasta (bijgerecht)","Pasta (hoofdgerecht)","Rijst","Wrap","Aardappelen","Wit brood","Bruin brood","Appelmoes","Sportdrank"]},
        "Tussendoor NM": {"pct": 0.083, "emoji": "🍎", "foods": ["Banaan","Fruit","Granenkoek","Peperkoek","Rijstwafel","Gedroogde abrikozen","Sportdrank"]},
        "Avondmaal":     {"pct": 0.25,  "emoji": "🍝", "foods": ["Pasta (bijgerecht)","Pasta (hoofdgerecht)","Rijst","Aardappelen","Couscous","Quinoa","Wrap","Appelmoes","Sportdrank"]},
        "Avond snack":   {"pct": 0.083, "emoji": "🌙", "foods": ["Rijstwafel","Peperkoek","Granenkoek","Banaan","Fruit","Sportdrank"]},
    }

    BOOST_TIPS = {
        "Ontbijt":    ["Extra lepel honing (+6g)", "Glas appelsap 200ml (+20g)", "Extra banaan (+25g)", "Snee wit brood met jam (+22g)"],
        "Lunch":      ["Extra sandwich met stroop (+24g)", "Potje appelmoes (+22g)", "Extra wrap (+25g)", "Drinkyoghurt 250ml (+25g)"],
        "Avondmaal":  ["Extra schep rijst/pasta (+12g)", "Glas limonade (+20g)", "Schaaltje sorbetijs (+30g)", "Wit brood bij maaltijd (+15g)"],
        "Tussendoor": ["Handvol winegums (+25g)", "Blikje cola 330ml (+35g)", "Twee rijstwafels met honing (+20g)", "Plak peperkoek (+18g)", "Gedroogde dadels 3 stuks (+18g)"],
    }

    def get_boost_tip(moment):
        cat = "Tussendoor" if ("Tussendoor" in moment or moment == "Avond snack") else moment
        pool = BOOST_TIPS.get(cat, BOOST_TIPS["Tussendoor"])
        return f"• {random.choice(pool)}"

    # ─── DAG TABS ─────────────────────────────────────────────────────────
    tab1, tab2 = st.tabs(["📅  DAG 1 — 2 dagen voor race", "📅  DAG 2 — dag voor race"])
    dag_totalen = {}

    for dag_idx, tab in enumerate([tab1, tab2], start=1):
        with tab:
            dag_kh = 0.0
            moments = list(MOMENT_CONFIGS.keys())
            left_col, right_col = st.columns(2)

            for col, moment_list in [(left_col, moments[:3]), (right_col, moments[3:])]:
                with col:
                    for moment in moment_list:
                        cfg = MOMENT_CONFIGS[moment]
                        target_m = round(dag_target * cfg["pct"])
                        moment_carbs = 0.0
                        items_list = []

                        # Card header
                        st.markdown(f"""
                        <div style="background:linear-gradient(135deg,#0f172a,#1a2540);
                             border:1px solid #1e293b; border-top:3px solid #f97316;
                             border-radius:12px 12px 0 0; padding:14px 16px 10px 16px; margin-bottom:0;">
                            <div style="display:flex; align-items:center; gap:8px;">
                                <span style="font-size:1.3rem;">{cfg['emoji']}</span>
                                <div>
                                    <div style="color:#f97316; font-weight:800; font-size:0.8rem; letter-spacing:0.05em;">
                                        {moment.upper()}
                                    </div>
                                    <div style="color:#64748b; font-size:0.72rem;">doel: {target_m}g KH</div>
                                </div>
                            </div>
                        </div>
                        <div style="background:#0d1525; border:1px solid #1e293b; border-top:none;
                             border-radius:0 0 12px 12px; padding:12px 14px 10px 14px; margin-bottom:14px;">
                        """, unsafe_allow_html=True)

                        # Food inputs
                        for food in cfg["foods"]:
                            info = FOOD_DB.get(food)
                            if not info:
                                continue
                            key = f"cl_{dag_idx}_{moment}_{food}"
                            col_a, col_b = st.columns([3, 2])
                            with col_a:
                                st.markdown(f"""
                                <div style='margin-bottom:2px;'>
                                    <div style='font-size:0.82rem; color:#e2e8f0; font-weight:600;'>{food}</div>
                                    <div style='font-size:0.7rem; color:#64748b;'>{info['label']}</div>
                                </div>""", unsafe_allow_html=True)
                            with col_b:
                                val = st.number_input(
                                    info['unit'],
                                    min_value=0.0, value=0.0, step=1.0,
                                    key=key,
                                    placeholder=info['unit'],
                                )
                            if val > 0:
                                c = round(val * info["carbs"])
                                moment_carbs += c
                                items_list.append(f"{val} {info['unit']} {food} ({c}g)")

                        # Custom products — unlimited, with delete
                        custom_key = f"custom_{dag_idx}_{moment}"
                        if custom_key not in st.session_state:
                            st.session_state[custom_key] = []

                        with st.expander("➕ Eigen product toevoegen"):
                            st.markdown("<div style='font-size:0.75rem; color:#f97316; margin-bottom:8px;'>Geef het aantal koolhydraten per portie in — zie verpakking.</div>", unsafe_allow_html=True)

                            to_delete = []
                            for ci, item in enumerate(st.session_state[custom_key]):
                                ca, cb, cc = st.columns([3, 2, 1])
                                with ca:
                                    nm = st.text_input("Naam", value=item["name"], key=f"{custom_key}_n{ci}", label_visibility="collapsed", placeholder="Naam product")
                                with cb:
                                    kh = st.number_input("g KH", value=item["carbs"], min_value=0.0, key=f"{custom_key}_k{ci}", label_visibility="collapsed", placeholder="g KH/portie")
                                with cc:
                                    if st.button("✕", key=f"{custom_key}_d{ci}"):
                                        to_delete.append(ci)
                                st.session_state[custom_key][ci] = {"name": nm, "carbs": kh}

                            for ci in reversed(to_delete):
                                st.session_state[custom_key].pop(ci)
                                st.rerun()

                            if st.button("+ Voeg toe", key=f"{custom_key}_add"):
                                st.session_state[custom_key].append({"name": "", "carbs": 0.0})
                                st.rerun()

                        for item in st.session_state.get(custom_key, []):
                            if item["name"] and item["carbs"] > 0:
                                moment_carbs += item["carbs"]
                                items_list.append(f"{item['name']} (eigen) {round(item['carbs'])}g")

                        dag_kh += moment_carbs

                        # Progress bar per moment
                        pct_m = min(100, round((moment_carbs / target_m) * 100)) if target_m > 0 else 0
                        bar_c = "#22c55e" if pct_m >= 90 else ("#fbbf24" if pct_m >= 60 else "#ef4444")

                        boost_html = ""
                        if moment_carbs > 0 and (target_m - moment_carbs) > 5:
                            tip = get_boost_tip(moment)
                            boost_html = f"""<div style="background:rgba(239,68,68,0.08); border:1px solid #ef4444;
                                border-radius:6px; padding:8px 10px; margin-top:6px; font-size:0.75rem; color:#fca5a5;">
                                💡 <strong>Booster tip:</strong> {tip}</div>"""

                        st.markdown(f"""
                        <div style="background:#1e293b; border-radius:4px; height:5px; margin:8px 0 2px 0;">
                            <div style="width:{pct_m}%; height:100%; background:{bar_c}; border-radius:4px;"></div>
                        </div>
                        <div style="font-size:0.7rem; color:#64748b;">{round(moment_carbs)}g / {target_m}g ({pct_m}%)</div>
                        {boost_html}
                        </div>
                        """, unsafe_allow_html=True)

            # Day total bar
            dag_pct = round((dag_kh / dag_target) * 100) if dag_target > 0 else 0
            bar_color = "#22c55e" if dag_pct >= 90 else ("#fbbf24" if dag_pct >= 70 else "#ef4444")
            status_emoji = "✅" if dag_pct >= 90 else ("⚡" if dag_pct >= 70 else "📉")
            status_msg = "Doel bereikt!" if dag_pct >= 90 else ("Bijna!" if dag_pct >= 70 else "Nog te laag")
            st.markdown(f"""
            <div style="background:linear-gradient(135deg,#1e293b,#0f172a); border:1px solid #334155;
                 border-radius:14px; padding:18px 20px; margin-top:4px;">
                <div style="display:flex; justify-content:space-between; align-items:center; margin-bottom:10px;">
                    <div style="font-weight:900; font-size:1rem; color:#f8fafc;">
                        {status_emoji} TOTAAL DAG {dag_idx}
                    </div>
                    <div style="font-weight:900; font-size:1.1rem; color:{bar_color};">
                        {round(dag_kh)}g <span style="color:#64748b; font-size:0.85rem;">/ {dag_target}g</span>
                    </div>
                </div>
                <div style="background:#334155; border-radius:8px; height:10px; overflow:hidden;">
                    <div style="width:{min(dag_pct,100)}%; height:100%; background:{bar_color}; border-radius:8px;"></div>
                </div>
                <div style="font-size:0.78rem; color:#94a3b8; margin-top:6px; text-align:right;">
                    {dag_pct}% — {status_msg}
                </div>
            </div>
            """, unsafe_allow_html=True)
            dag_totalen[f"dag{dag_idx}"] = {"totaal": round(dag_kh), "target": dag_target, "pct": dag_pct}

    st.markdown("<br>", unsafe_allow_html=True)
    col_prev, col_next = st.columns(2)
    with col_prev:
        if st.button("Vorige", key="cl_prev"):
            st.session_state.coach_stap = 2
            st.rerun()
    with col_next:
        if st.button("Volgende", key="cl_next", use_container_width=True):
            st.session_state.coach_data.update({
                "carboloading": dag_totalen, "dag_target": dag_target, "factor": factor,
            })
            st.session_state.coach_stap = 4
            st.rerun()

# ─── STAP 4: RACEDAG ─────────────────────────────────────────────────────────
def _stap_racedag():
    data = st.session_state.get("coach_data", {})
    start_time_str = data.get("start_time", "09:00")
    _coach_bubble(f"""
    Perfect! Nu plannen we jouw <strong>racedagvoeding</strong> — het ontbijt en de pre-race strategie
    vóór de start om {start_time_str}.<br><br>
    Het doel is om met volle glycogeenvoorraden aan de start te staan, maar zonder
    een vol of zwaar gevoel in de maag.
    """)
    start_dt = datetime.strptime(start_time_str, "%H:%M")
    onbijt_tips = {
        "3-4 uur voor start (aanbevolen)": -210,
        "2-3 uur voor start": -150,
        "1-2 uur voor start (licht)": -90,
    }
    ontbijt_keuze = st.selectbox("Wanneer eet je ontbijt?", list(onbijt_tips.keys()), key="rd_ontbijt_timing")
    offset = onbijt_tips[ontbijt_keuze]
    ontbijt_tijd = (start_dt + timedelta(minutes=offset)).strftime("%H:%M")
    st.markdown(f"""
    <div style="background:rgba(34,197,94,0.1); border:1px solid #22c55e; padding:10px 14px;
         border-radius:8px; margin-bottom:16px; color:#86efac; font-size:0.85rem;">
        Ontbijt om: <strong>{ontbijt_tijd}</strong> &nbsp;|&nbsp; Start om: <strong>{start_time_str}</strong>
    </div>
    """, unsafe_allow_html=True)

    col1, col2 = st.columns(2)
    with col1:
        st.markdown("<div style='color:#3b82f6; font-weight:700; font-size:0.82rem; margin-bottom:8px;'>ONTBIJT KOOLHYDRATEN</div>", unsafe_allow_html=True)
        ontbijt_kh = st.number_input("KH ontbijt (gram)", 0, 300, data.get("ontbijt_kh", 100), 10, key="rd_ontkh", label_visibility="collapsed")
        koffie = st.checkbox("Koffie (cafeïne ~95mg)", value=data.get("koffie", True), key="rd_koffie")
        sportdrank_ont = st.checkbox("Sportdrank 500ml (+35g KH)", value=data.get("sportdrank_ont", False), key="rd_sdont")
    with col2:
        st.markdown("<div style='color:#f97316; font-weight:700; font-size:0.82rem; margin-bottom:8px;'>PRE-RACE (30-60min voor start)</div>", unsafe_allow_html=True)
        pre_gel = st.checkbox("Pre-race gel (+22-25g KH)", value=data.get("pre_gel", True), key="rd_pregel")
        pre_kh_extra = st.number_input("Extra KH pre-race (g)", 0, 100, data.get("pre_kh_extra", 0), 5, key="rd_prekh", label_visibility="collapsed")
        cafeine_timing = st.selectbox("Cafeïne strategie", [
            "Geen cafeïne", "Enkel koffie ontbijt",
            "Koffie + gel met cafeïne (uur 2)", "Meerdere cafeïne gels verspreid",
        ], index=data.get("cafeine_idx", 1), key="rd_cafe_strat")

    pre_totaal = ontbijt_kh + (35 if sportdrank_ont else 0) + (23 if pre_gel else 0) + pre_kh_extra
    gewicht = data.get("gewicht", 70)
    ideaal_min, ideaal_max = round(gewicht * 1), round(gewicht * 3)
    status = "Goed!" if ideaal_min <= pre_totaal <= ideaal_max else ("Mogelijk te veel" if pre_totaal > ideaal_max else "Te weinig")
    st.markdown(f"""
    <div style="background:#1e293b; border-radius:12px; padding:16px; margin:16px 0; text-align:center;">
        <div style="color:#94a3b8; font-size:0.78rem; margin-bottom:4px;">TOTAAL KH VOOR DE START</div>
        <div style="font-size:1.5rem; font-weight:900; color:#f97316;">{pre_totaal}g</div>
        <div style="font-size:0.82rem; color:#64748b; margin-top:4px;">Ideaal: {ideaal_min}–{ideaal_max}g &nbsp; {status}</div>
    </div>
    """, unsafe_allow_html=True)

    col_prev, col_next = st.columns(2)
    with col_prev:
        if st.button("Vorige", key="rd_prev"):
            st.session_state.coach_stap = 3
            st.rerun()
    with col_next:
        if st.button("Volgende", key="rd_next", use_container_width=True):
            st.session_state.coach_data.update({
                "ontbijt_kh": ontbijt_kh, "ontbijt_timing": ontbijt_keuze,
                "ontbijt_tijd": ontbijt_tijd, "koffie": koffie,
                "sportdrank_ont": sportdrank_ont, "pre_gel": pre_gel,
                "pre_kh_extra": pre_kh_extra, "cafeine_strategie": cafeine_timing,
                "cafeine_idx": ["Geen cafeïne","Enkel koffie ontbijt",
                    "Koffie + gel met cafeïne (uur 2)","Meerdere cafeïne gels verspreid"].index(cafeine_timing),
                "pre_totaal_kh": pre_totaal,
            })
            st.session_state.coach_stap = 5
            st.rerun()


# ─── STAP 5: RACEPLAN ────────────────────────────────────────────────────────
def _stap_raceplan():
    data = st.session_state.get("coach_data", {})
    _coach_bubble("""
    Bijna klaar! Voeg nu de <strong>producten toe die je tijdens de race</strong> gaat gebruiken.
    Op basis hiervan bouw ik een <strong>uur-per-uur raceplan</strong> met exacte hoeveelheden en timing.
    """)
    pcol1, pcol2 = st.columns(2)
    with pcol1:
        st.markdown("<div style='color:#3b82f6; font-weight:700; font-size:0.82rem; margin-bottom:8px;'>SPORTDRANK (per 500ml)</div>", unsafe_allow_html=True)
        n_drank = st.number_input("Aantal dranksoorten", 0, 5, 1, key="rp_n_drank", label_visibility="collapsed")
        drank_pool = []
        for i in range(int(n_drank)):
            c1, c2 = st.columns([2,1])
            with c1: naam = st.text_input(f"Naam drank {i+1}", key=f"rp_drank_{i}", placeholder="bijv. Maurten 320")
            with c2: kh = st.number_input("KH/500ml", key=f"rp_dkh_{i}", min_value=0, value=70)
            if naam: drank_pool.append({"name": naam, "kh": kh, "type": "drank"})

        st.markdown("<div style='color:#10b981; font-weight:700; font-size:0.82rem; margin:12px 0 8px 0;'>VASTE VOEDING</div>", unsafe_allow_html=True)
        n_vast = st.number_input("Aantal vaste voeding", 0, 5, 0, key="rp_n_vast", label_visibility="collapsed")
        vast_pool = []
        for i in range(int(n_vast)):
            c1, c2 = st.columns([2,1])
            with c1: naam = st.text_input(f"Naam vast {i+1}", key=f"rp_vast_{i}", placeholder="bijv. Banaan")
            with c2: kh = st.number_input("KH", key=f"rp_vkh_{i}", min_value=0, value=25)
            if naam: vast_pool.append({"name": naam, "kh": kh, "type": "vast"})

    with pcol2:
        st.markdown("<div style='color:#60a5fa; font-weight:700; font-size:0.82rem; margin-bottom:8px;'>ENERGY GELS</div>", unsafe_allow_html=True)
        n_gels = st.number_input("Aantal gels", 0, 5, 1, key="rp_n_gels", label_visibility="collapsed")
        gels_pool = []
        for i in range(int(n_gels)):
            c1, c2 = st.columns([2,1])
            with c1: naam = st.text_input(f"Naam gel {i+1}", key=f"rp_gel_{i}", placeholder="bijv. SIS Go Gel")
            with c2: kh = st.number_input("KH gel", key=f"rp_gkh_{i}", min_value=0, value=22)
            if naam: gels_pool.append({"name": naam, "kh": kh, "type": "gels"})

        st.markdown("<div style='color:#f59e0b; font-weight:700; font-size:0.82rem; margin:12px 0 8px 0;'>GELS + CAFEÏNE</div>", unsafe_allow_html=True)
        n_cafe = st.number_input("Aantal cafeïne gels", 0, 5, 0, key="rp_n_cafe", label_visibility="collapsed")
        cafe_pool = []
        for i in range(int(n_cafe)):
            c1, c2 = st.columns([2,1])
            with c1: naam = st.text_input(f"Naam caf {i+1}", key=f"rp_cafe_{i}", placeholder="bijv. Caffeine Gel")
            with c2: kh = st.number_input("KH caf", key=f"rp_ckh_{i}", min_value=0, value=25)
            if naam: cafe_pool.append({"name": naam, "kh": kh, "type": "cafe"})

    pool = {
        "drank": sorted(drank_pool, key=lambda x: x["kh"], reverse=True),
        "gels": sorted(gels_pool, key=lambda x: x["kh"], reverse=True),
        "cafe": cafe_pool, "vast": vast_pool,
    }
    col_prev, col_gen = st.columns(2)
    with col_prev:
        if st.button("Vorige", key="rp_prev"):
            st.session_state.coach_stap = 4
            st.rerun()
    with col_gen:
        if st.button("GENEREER VOLLEDIG PLAN", key="rp_gen", use_container_width=True):
            st.session_state.coach_data["pool"] = pool
            st.session_state.coach_stap = 6
            st.rerun()


# ─── STAP 6: SAMENVATTING ────────────────────────────────────────────────────
def _stap_samenvatting():
    data = st.session_state.get("coach_data", {})
    naam = st.session_state.get("current_user", {}).get("name", "Atleet")

    _coach_bubble(f"""
    Super gedaan, <strong>{naam}!</strong> Hier is jouw <strong>volledig gepersonaliseerd race nutrition plan</strong>.
    Bewaar dit goed en volg het stap voor stap op raceday!
    """)

    c1, c2, c3, c4 = st.columns(4)
    info_items = [
        (c1, "Atleet", naam, "#f97316"),
        (c2, "Sport", f"{SPORT_ICONS.get(data.get('sport',''),'')} {data.get('sport','—')}", "#3b82f6"),
        (c3, "Wedstrijd", data.get("wedstrijd_datum","—"), "#22c55e"),
        (c4, "Duur", f"{data.get('totale_min',0)//60}u{data.get('totale_min',0)%60:02d}m", "#8b5cf6"),
    ]
    for col, lbl, val, color in info_items:
        with col:
            st.markdown(f"""
            <div style="text-align:center; padding:10px; background:#0f172a; border-radius:10px; border-top:3px solid {color}; margin-bottom:16px;">
                <div style="font-size:0.62rem; color:#64748b; font-weight:700; letter-spacing:1px;">{lbl.upper()}</div>
                <div style="font-size:0.95rem; font-weight:800; color:#f8fafc; margin-top:4px;">{val}</div>
            </div>
            """, unsafe_allow_html=True)

    tab_cl, tab_race, tab_plan = st.tabs(["CARBOLOADING", "RACEDAG", "RACEPLAN"])

    with tab_cl:
        factor = data.get("factor", 8)
        dag_target = data.get("dag_target", 0)
        cl_data = data.get("carboloading", {})
        st.markdown(f"""
        <div style="background:rgba(249,115,22,0.1); border:1px solid #f97316; padding:14px;
             border-radius:10px; margin-bottom:16px; text-align:center; color:#fb923c; font-weight:700;">
            Protocol: {factor}g KH/kg/dag &nbsp;|&nbsp; Dagdoel: {dag_target}g KH &nbsp;|&nbsp; Gewicht: {data.get("gewicht",70)}kg
        </div>
        """, unsafe_allow_html=True)
        for dag_key, dag_label in [("dag1","DAG 1 — 2 dagen voor race"),("dag2","DAG 2 — dag voor race")]:
            dag_info = cl_data.get(dag_key, {})
            totaal = dag_info.get("totaal", 0)
            pct = dag_info.get("pct", 0)
            bar_color = "#22c55e" if pct >= 90 else ("#fbbf24" if pct >= 70 else "#ef4444")
            st.markdown(f"""
            <div style="background:#1e293b; border-radius:12px; padding:16px; margin-bottom:12px;">
                <div style="font-weight:800; color:#f8fafc; margin-bottom:8px;">{dag_label}</div>
                <div style="background:#334155; border-radius:8px; height:10px; overflow:hidden;">
                    <div style="width:{min(pct,100)}%; height:100%; background:{bar_color}; border-radius:8px;"></div>
                </div>
                <div style="font-size:0.82rem; color:#94a3b8; margin-top:6px;">{totaal}g / {dag_target}g — {pct}%</div>
            </div>
            """, unsafe_allow_html=True)

    with tab_race:
        ontbijt_kh = data.get("ontbijt_kh", 0)
        pre_totaal = data.get("pre_totaal_kh", 0)
        st.markdown(f"""
        <div style="background:#1e293b; border-radius:12px; padding:20px; margin-bottom:16px;">
            <div style="color:#f97316; font-weight:800; margin-bottom:12px;">ONTBIJT om {data.get("ontbijt_tijd","—")}</div>
            <div style="color:#f8fafc;">{ontbijt_kh}g koolhydraten &nbsp;|&nbsp; {"Koffie" if data.get("koffie") else "Geen koffie"} &nbsp;|&nbsp; {"+ Sportdrank 500ml" if data.get("sportdrank_ont") else ""}</div>
        </div>
        <div style="background:#1e293b; border-radius:12px; padding:20px;">
            <div style="color:#3b82f6; font-weight:800; margin-bottom:12px;">PRE-RACE (30-60min voor start)</div>
            <div style="color:#f8fafc;">{"Pre-race gel" if data.get("pre_gel") else "Geen gel"} &nbsp;|&nbsp; {data.get("pre_kh_extra",0)}g extra KH &nbsp;|&nbsp; Totaal: <strong style="color:#f97316;">{pre_totaal}g KH</strong></div>
        </div>
        """, unsafe_allow_html=True)

    with tab_plan:
        pool = data.get("pool", {})
        totale_min = data.get("totale_min", 180)
        min_kh = data.get("min_kh", 60)
        max_kh = data.get("max_kh", 90)
        start_str = data.get("start_time", "09:00")
        start_dt = datetime.strptime(start_str, "%H:%M")
        n_uur = math.ceil(totale_min / 60)

        alle_producten = (
            pool.get("drank", []) + pool.get("gels", []) +
            pool.get("cafe", []) + pool.get("vast", [])
        )

        if not alle_producten:
            st.info("Geen producten opgegeven. Ga terug naar stap Raceplan om producten toe te voegen.")
        else:
            for uur in range(n_uur):
                uur_start = (start_dt + timedelta(hours=uur)).strftime("%H:%M")
                uur_eind_min = min((uur + 1) * 60, totale_min)
                product = alle_producten[uur % len(alle_producten)]
                kh_uur = product["kh"]
                status_c = "#22c55e" if min_kh <= kh_uur <= max_kh else ("#f97316" if kh_uur < min_kh else "#ef4444")
                st.markdown(f"""
                <div style="background:#0f172a; border:1px solid #1e293b; border-radius:12px;
                     padding:14px 18px; margin-bottom:10px; display:flex; justify-content:space-between; align-items:center;">
                    <div>
                        <div style="color:#94a3b8; font-size:0.72rem; font-weight:700; letter-spacing:1px;">UUR {uur+1} — {uur_start}</div>
                        <div style="color:#f8fafc; font-weight:700; margin-top:4px;">{product["name"]}</div>
                    </div>
                    <div style="text-align:right;">
                        <div style="font-size:1.2rem; font-weight:900; color:{status_c};">{kh_uur}g KH</div>
                        <div style="font-size:0.68rem; color:#64748b;">doel: {min_kh}–{max_kh}g</div>
                    </div>
                </div>
                """, unsafe_allow_html=True)

    st.markdown("<br>", unsafe_allow_html=True)
    if st.button("Nieuw plan starten", key="sam_reset"):
        st.session_state.coach_stap = 0
        st.session_state.coach_data = {}
        st.rerun()


# ─── HOOFD RENDER FUNCTIE ────────────────────────────────────────────────────
def render_coach():
    if "coach_stap" not in st.session_state:
        st.session_state.coach_stap = 0
    if "coach_data" not in st.session_state:
        st.session_state.coach_data = {}

    stap = st.session_state.coach_stap
    naam = st.session_state.get("current_user", {}).get("name", "Atleet")

    _progress_bar(stap)

    if stap == 0:   _stap_welkom(naam)
    elif stap == 1: _stap_profiel(naam)
    elif stap == 2: _stap_wedstrijd()
    elif stap == 3: _stap_carboloading()
    elif stap == 4: _stap_racedag()
    elif stap == 5: _stap_raceplan()
    elif stap == 6: _stap_samenvatting()
